import { createTheme } from '@mui/material/styles';

// Premium Solar Theme Colors
const solarTheme = {
  primary: '#FFA500',      // Solar Orange
  secondary: '#2B7A0B',    // Eco Green
  accent: '#1E293B',       // Dark Slate
  background: '#F2F7F5',   // Soft Eco White
  text: '#0F172A',         // Dark Text
};

// Light Theme
export const lightTheme = createTheme({
  palette: {
    mode: 'light',
    primary: {
      main: solarTheme.primary,
      light: '#FFB84D',
      dark: '#E69400',
      contrastText: '#FFFFFF',
    },
    secondary: {
      main: solarTheme.secondary,
      light: '#4A9B2E',
      dark: '#1F5A08',
      contrastText: '#FFFFFF',
    },
    accent: {
      main: solarTheme.accent,
      light: '#334155',
      dark: '#0F172A',
    },
    background: {
      default: solarTheme.background,
      paper: '#FFFFFF',
    },
    text: {
      primary: solarTheme.text,
      secondary: '#64748B',
    },
  },
  typography: {
    fontFamily: "'Inter', 'Roboto', 'Helvetica', 'Arial', sans-serif",
    h1: {
      fontWeight: 800,
      fontSize: '3.5rem',
      lineHeight: 1.2,
      '@media (max-width:768px)': {
        fontSize: '2.5rem',
      },
    },
    h2: {
      fontWeight: 700,
      fontSize: '2.75rem',
      lineHeight: 1.3,
      '@media (max-width:768px)': {
        fontSize: '2rem',
      },
    },
    h3: {
      fontWeight: 600,
      fontSize: '2rem',
      lineHeight: 1.4,
    },
    h4: {
      fontWeight: 600,
      fontSize: '1.5rem',
      lineHeight: 1.4,
    },
    h5: {
      fontWeight: 600,
      fontSize: '1.25rem',
    },
    h6: {
      fontWeight: 600,
      fontSize: '1rem',
    },
    body1: {
      fontSize: '1rem',
      lineHeight: 1.7,
    },
    body2: {
      fontSize: '0.875rem',
      lineHeight: 1.6,
    },
    button: {
      textTransform: 'none',
      fontWeight: 600,
      fontSize: '1rem',
    },
  },
  shape: {
    borderRadius: 12,
  },
  shadows: [
    'none',
    '0px 2px 4px rgba(0,0,0,0.05)',
    '0px 4px 8px rgba(0,0,0,0.08)',
    '0px 8px 16px rgba(0,0,0,0.1)',
    '0px 12px 24px rgba(0,0,0,0.12)',
    '0px 16px 32px rgba(0,0,0,0.15)',
    ...Array(19).fill('none'),
  ],
  components: {
    MuiButton: {
      styleOverrides: {
        root: {
          borderRadius: 12,
          padding: '12px 32px',
          fontSize: '1rem',
          fontWeight: 600,
          boxShadow: '0px 4px 12px rgba(255, 165, 0, 0.3)',
          '&:hover': {
            boxShadow: '0px 6px 16px rgba(255, 165, 0, 0.4)',
          },
        },
        outlined: {
          borderWidth: 2,
          '&:hover': {
            borderWidth: 2,
          },
        },
      },
    },
    MuiCard: {
      styleOverrides: {
        root: {
          borderRadius: 16,
          boxShadow: '0px 4px 20px rgba(0,0,0,0.08)',
          transition: 'all 0.3s ease-in-out',
          '&:hover': {
            boxShadow: '0px 8px 30px rgba(0,0,0,0.12)',
            transform: 'translateY(-4px)',
          },
        },
      },
    },
    MuiAppBar: {
      styleOverrides: {
        root: {
          boxShadow: '0px 2px 10px rgba(0,0,0,0.08)',
          backdropFilter: 'blur(10px)',
          backgroundColor: 'rgba(255, 255, 255, 0.95)',
        },
      },
    },
  },
});

// Dark Theme
export const darkTheme = createTheme({
  ...lightTheme,
  palette: {
    mode: 'dark',
    primary: {
      main: solarTheme.primary,
      light: '#FFB84D',
      dark: '#E69400',
      contrastText: '#FFFFFF',
    },
    secondary: {
      main: solarTheme.secondary,
      light: '#4A9B2E',
      dark: '#1F5A08',
      contrastText: '#FFFFFF',
    },
    accent: {
      main: solarTheme.accent,
      light: '#334155',
      dark: '#0F172A',
    },
    background: {
      default: '#0F172A',
      paper: '#1E293B',
    },
    text: {
      primary: '#F2F7F5',
      secondary: '#94A3B8',
    },
  },
  components: {
    ...lightTheme.components,
    MuiAppBar: {
      styleOverrides: {
        root: {
          boxShadow: '0px 2px 10px rgba(0,0,0,0.3)',
          backgroundColor: 'rgba(30, 41, 59, 0.95)',
        },
      },
    },
  },
});

